   162  func (mg *Migrator) GetMigrationLog() (map[string]MigrationLog, error) {
   163          logMap := make(map[string]MigrationLog)
   164          logItems := make([]MigrationLog, 0)
   165          if err := mg.DBEngine.Table(mg.tableName).Find(&logItems); err != nil {
   166                  return nil, err
   167          }
   168
   169          for _, logItem := range logItems {
   170                  if !logItem.Success {
   171                          continue
   172                  }
   173                  logMap[logItem.MigrationID] = logItem
   174          }
   175
   176          mg.logMap = logMap
   177          return logMap, nil
   178  }
