    34  // NewRawSQLMigration should be used carefully, the usage
    35  // of SQL statements that cause breaking changes like renaming
    36  // a table or a column, or changing a column type should not be used.
    37  func NewRawSQLMigration(sql string) *RawSQLMigration {
    38          m := &RawSQLMigration{}
    39          if sql != "" {
    40                  m.Default(sql)
    41          }
    42          return m
    43  }
