    45  func (m *RawSQLMigration) SQL(dialect Dialect) string {
    46          if m.sql != nil {
    47                  if val := m.sql[dialect.DriverName()]; val != "" {
    48                          return val
    49                  }
    50
    51                  if val := m.sql["default"]; val != "" {
    52                          return val
    53                  }
    54          }
    55
    56          return ""
    57  }
    58
    59  func (m *RawSQLMigration) Set(dialect string, sql string) *RawSQLMigration {
    60          if m.sql == nil {
    61                  m.sql = make(map[string]string)
    62          }
    63
    64          m.sql[dialect] = sql
    65          return m
    66  }
