   191  func NewAddTableMigration(table Table) *AddTableMigration {
   192          for _, col := range table.Columns {
   193                  if col.IsPrimaryKey {
   194                          table.PrimaryKeys = append(table.PrimaryKeys, col.Name)
   195                  }
   196          }
   197          return &AddTableMigration{table: table}
   198  }
