   187  func (b *BaseDialect) CreateTableSQL(table *Table) string {
   188          sql := "CREATE TABLE IF NOT EXISTS "
   189          sql += b.dialect.Quote(table.Name) + " (\n"
   190
   191          pkList := table.PrimaryKeys
   192
   193          for _, col := range table.Columns {
   194                  if col.IsPrimaryKey && len(pkList) == 1 {
   195                          sql += col.String(b.dialect)
   196                  } else {
   197                          sql += col.StringNoPk(b.dialect)
   198                  }
   199                  sql = strings.TrimSpace(sql)
   200                  sql += "\n, "
   201          }
   202
   203          if len(pkList) > 1 {
   204                  quotedCols := []string{}
   205                  for _, col := range pkList {
   206                          quotedCols = append(quotedCols, b.dialect.Quote(col))
   207                  }
   208
   209                  sql += "PRIMARY KEY ( " + strings.Join(quotedCols, ",") + " ), "
   210          }
   211
   212          sql = sql[:len(sql)-2] + ")"
   213          if b.dialect.SupportEngine() {
   214                  sql += " ENGINE=InnoDB DEFAULT CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci"
   215          }
   216
   217          sql += ";"
   218          return sql
   219  }
