   236  func (db *MySQLDialect) UpsertMultipleSQL(tableName string, keyCols, updateCols []string, count int) (string, error) {
   237          if count < 1 {
   238                  return "", fmt.Errorf("upsert statement must have count >= 1. Got %v", count)
   239          }
   240          columnsStr := strings.Builder{}
   241          colPlaceHoldersStr := strings.Builder{}
   242          setStr := strings.Builder{}
   243
   244          separator := ", "
   245          for i, c := range updateCols {
   246                  if i == len(updateCols)-1 {
   247                          separator = ""
   248                  }
   249                  columnsStr.WriteString(fmt.Sprintf("%s%s", db.Quote(c), separator))
   250                  colPlaceHoldersStr.WriteString(fmt.Sprintf("?%s", separator))
   251                  setStr.WriteString(fmt.Sprintf("%s=VALUES(%s)%s", db.Quote(c), db.Quote(c), separator))
   252          }
   253
   254          valuesStr := strings.Builder{}
   255          separator = ", "
   256          colPlaceHolders := colPlaceHoldersStr.String()
   257          for i := 0; i < count; i++ {
   258                  if i == count-1 {
   259                          separator = ""
   260                  }
   261                  valuesStr.WriteString(fmt.Sprintf("(%s)%s", colPlaceHolders, separator))
   262          }
   263
   264          s := fmt.Sprintf(`INSERT INTO %s (%s) VALUES %s ON DUPLICATE KEY UPDATE %s`,
   265                  tableName,
   266                  columnsStr.String(),
   267                  valuesStr.String(),
   268                  setStr.String(),
   269          )
   270          return s, nil
   271  }
   272
   273  func (db *MySQLDialect) Lock(cfg LockCfg) error {
   274          query := "SELECT GET_LOCK(?, ?)"
   275          var success sql.NullBool
   276
   277          // trying to obtain the lock with the specific name
   278          // the lock is exclusive per session and is released explicitly by executing RELEASE_LOCK() or implicitly when the session terminates
   279          // it returns 1 if the lock was obtained successfully,
   280          // 0 if the attempt timed out (for example, because another client has previously locked the name),
   281          // or NULL if an error occurred
   282          // starting from MySQL 5.7 it is even possible for a given session to acquire multiple locks for the same name
   283          // however other sessions cannot acquire a lock with that name until the acquiring session releases all its locks for the name.
   284          _, err := cfg.Session.SQL(query, cfg.Key, cfg.Timeout).Get(&success)
   285          if err != nil {
   286                  return err
   287          }
   288          if !success.Valid || !success.Bool {
   289                  return ErrLockDB
   290          }
   291          return nil
   292  }
   293
   294  func (db *MySQLDialect) Unlock(cfg LockCfg) error {
   295          query := "SELECT RELEASE_LOCK(?)"
   296          var success sql.NullBool
   297
   298          // trying to release the lock with the specific name
   299          // it returns 1 if the lock was released,
   300          // 0 if the lock was not established by this thread (in which case the lock is not released),
   301          // and NULL if the named lock did not exist (it was never obtained by a call to GET_LOCK() or if it has previously been released)
   302          _, err := cfg.Session.SQL(query, cfg.Key).Get(&success)
   303          if err != nil {
   304                  return err
   305          }
   306          if !success.Valid || !success.Bool {
   307                  return ErrReleaseLockDB
   308          }
   309          return nil
   310  }
   311
   312  func (db *MySQLDialect) GetDBName(dsn string) (string, error) {
   313          cfg, err := mysql.ParseDSN(dsn)
   314          if err != nil {
   315                  return "", err
   316          }
   317
   318          return cfg.DBName, nil
   319  }

