   234  // UpsertMultipleSQL returns the upsert sql statement for PostgreSQL dialect
   235  func (db *PostgresDialect) UpsertMultipleSQL(tableName string, keyCols, updateCols []string, count int) (string, error) {
   236          if count < 1 {
   237                  return "", fmt.Errorf("upsert statement must have count >= 1. Got %v", count)
   238          }
   239          columnsStr := strings.Builder{}
   240          onConflictStr := strings.Builder{}
   241          setStr := strings.Builder{}
   242
   243          const separator = ", "
   244          separatorVar := separator
   245          for i, c := range updateCols {
   246                  if i == len(updateCols)-1 {
   247                          separatorVar = ""
   248                  }
   249
   250                  columnsStr.WriteString(fmt.Sprintf("%s%s", db.Quote(c), separatorVar))
   251                  setStr.WriteString(fmt.Sprintf("%s=EXCLUDED.%s%s", db.Quote(c), db.Quote(c), separatorVar))
   252          }
   253
   254          separatorVar = separator
   255          for i, c := range keyCols {
   256                  if i == len(keyCols)-1 {
   257                          separatorVar = ""
   258                  }
   259                  onConflictStr.WriteString(fmt.Sprintf("%s%s", db.Quote(c), separatorVar))
   260          }
   261
   262          valuesStr := strings.Builder{}
   263          separatorVar = separator
   264          nextPlaceHolder := 1
   265
   266          for i := 0; i < count; i++ {
   267                  if i == count-1 {
   268                          separatorVar = ""
   269                  }
   270
   271                  colPlaceHoldersStr := strings.Builder{}
   272                  placeHolderSep := separator
   273                  for j := 1; j <= len(updateCols); j++ {
   274                          if j == len(updateCols) {
   275                                  placeHolderSep = ""
   276                          }
   277                          placeHolder := fmt.Sprintf("$%v%s", nextPlaceHolder, placeHolderSep)
   278                          nextPlaceHolder++
   279                          colPlaceHoldersStr.WriteString(placeHolder)
   280                  }
   281                  colPlaceHolders := colPlaceHoldersStr.String()
   282
   283                  valuesStr.WriteString(fmt.Sprintf("(%s)%s", colPlaceHolders, separatorVar))
   284          }
   285
   286          s := fmt.Sprintf(`INSERT INTO %s (%s) VALUES %s ON CONFLICT (%s) DO UPDATE SET %s;`,
   287                  tableName,
   288                  columnsStr.String(),
   289                  valuesStr.String(),
   290                  onConflictStr.String(),
   291                  setStr.String(),
   292          )
   293
   294          return s, nil
   295  }
