   317  // OrderBy normalizes ordering so that nulls end up last in sorting, which they do by default in both sqlite and mysql but not postgres
   318  // order should be a string like `dashboard.id ASC`
   319  func (db *PostgresDialect) OrderBy(order string) string {
   320          nullSort := "FIRST"
   321          normalizedOrder := strings.ToUpper(strings.TrimSpace(order))
   322
   323          if strings.HasSuffix(normalizedOrder, " DESC") {
   324                  nullSort = "LAST"
   325          }
   326
   327          return fmt.Sprintf("%s NULLS %s", order, nullSort)
   328  }
