   330  func (db *PostgresDialect) Unlock(cfg LockCfg) error {
   331          // trying to release a previously-acquired exclusive session level advisory lock.
   332          // it will either return true if the lock is successfully released or
   333          // false if the lock was not held (in addition an SQL warning will be reported by the server)
   334          query := "SELECT pg_advisory_unlock(?)"
   335          var success bool
   336
   337          _, err := cfg.Session.SQL(query, cfg.Key).Get(&success)
   338          if err != nil {
   339                  return err
   340          }
   341          if !success {
   342                  return ErrReleaseLockDB
   343          }
   344          return nil
   345  }
