   112  // TruncateDBTables deletes all data from all the tables and resets the sequences.
   113  // A special case is the dashboard_acl table where we keep the default permissions.
   114  func (db *SQLite3) TruncateDBTables(engine *xorm.Engine) error {
   115          tables, err := engine.Dialect().GetTables()
   116          if err != nil {
   117                  return err
   118          }
   119
   120          sess := engine.NewSession()
   121          defer sess.Close()
   122
   123          for _, table := range tables {
   124                  switch table.Name {
   125                  case "migration_log":
   126                          continue
   127                  case "dashboard_acl":
   128                          // keep default dashboard permissions
   129                          if _, err := sess.Exec(fmt.Sprintf("DELETE FROM %q WHERE dashboard_id != -1 AND org_id != -1;", table.Name)); err != nil {
   130                                  return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
   131                          }
   132                          if _, err := sess.Exec("UPDATE sqlite_sequence SET seq = 2 WHERE name = '%s';", table.Name); err != nil {
   133                                  return fmt.Errorf("failed to cleanup sqlite_sequence: %w", err)
   134                          }
   135                  default:
   136                          if _, err := sess.Exec(fmt.Sprintf("DELETE FROM %s;", table.Name)); err != nil {
   137                                  return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
   138                          }
   139                  }
   140          }
   141          if _, err := sess.Exec("UPDATE sqlite_sequence SET seq = 0 WHERE name != 'dashboard_acl';"); err != nil {
   142                  // if we have not created any autoincrement columns in the database this will fail, the error is expected and we can ignore it
   143                  // we can't discriminate based on code because sqlite returns a generic error code
   144                  if err.Error() != "no such table: sqlite_sequence" {
   145                          return fmt.Errorf("failed to cleanup sqlite_sequence: %w", err)
   146                  }
   147          }
   148          return nil
   149  }
